renderDocumentOptions.variables:
={
  "recipientName": "{{ $('Set Form Variables').item.json.recipientName }}",
  "EmployeeID": "{{ $('Set Form Variables').item.json.employeeId }}",
  "awardMonth": "{{ $('Set Form Variables').item.json.awardMonth }}",
  "achivements": {
    "type": "table",
    "columns": ["Achievement", "Description"],
    "data": {{ $('Set Form Variables').first().json.achievementsRaw.split(',').map(s => s.trim()).filter(s => s.length > 0).map(s => { const parts = s.split(':'); return [parts[0]?.trim() || '', (parts[1] || '').trim()]; }).toJsonString() }}
  },
  "profilePhoto": {
    "type": "image",
    "src": "{{ $('Set Form Variables').first().json.profilePhotoUrl }}",
    "width": 100,
    "align": "center"
  },
  "Signature": {
    "type": "image",
    "src": "{{ $('Set Form Variables').first().json.signatureUrl }}",
    "height": 50,
    "width": 100
  }
}

